```kotlin
// ImageUtils.kt
import android.content.Context
import android.graphics.Bitmap
import android.graphics.Matrix
import android.media.Image
import android.renderscript.Allocation
import android.renderscript.Element
import android.renderscript.RenderScript
import android.renderscript.ScriptIntrinsicYuvToRGB
import java.nio.ByteBuffer

object ImageUtils {
  fun yuvToBitmap(context: Context, image: Image, rotationDegrees: Int = 0): Bitmap {
    val yBuffer = image.planes[0].buffer
    val uBuffer = image.planes[1].buffer
    val vBuffer = image.planes[2].buffer

    val ySize = yBuffer.remaining()
    val uSize = uBuffer.remaining()
    val vSize = vBuffer.remaining()

    val nv21 = ByteArray(ySize + uSize + vSize)
    yBuffer.get(nv21, 0, ySize)

    // UV are typically interleaved differently; convert to NV21 (VU)
    val pixelStride = image.planes[1].pixelStride
    val rowStride = image.planes[1].rowStride
    var offset = ySize
    val width = image.width
    val height = image.height
    val chromaHeight = height / 2
    val uPlane = ByteArray(uSize)
    val vPlane = ByteArray(vSize)
    uBuffer.get(uPlane)
    vBuffer.get(vPlane)

    // Fill NV21 VU
    var pos = 0
    for (row in 0 until chromaHeight) {
      for (col in 0 until width / 2) {
        nv21[offset + pos] = vPlane[row * rowStride + col * pixelStride]
        nv21[offset + pos + 1] = uPlane[row * rowStride + col * pixelStride]
        pos += 2
      }
    }

    val rs = RenderScript.create(context)
    val yuvType = android.renderscript.Type.Builder(rs, Element.U8(rs)).setX(nv21.size)
    val inAlloc = Allocation.createTyped(rs, yuvType.create(), Allocation.USAGE_SCRIPT)
    inAlloc.copyFrom(nv21)
    val outType = android.renderscript.Type.Builder(rs, Element.RGBA_8888(rs)).setX(width).setY(height)
    val outAlloc = Allocation.createTyped(rs, outType.create(), Allocation.USAGE_SCRIPT)
    val yuvToRgb = ScriptIntrinsicYuvToRGB.create(rs, Element.U8_4(rs))
    yuvToRgb.setInput(inAlloc)
    yuvToRgb.forEach(outAlloc)
    val bmp = Bitmap.createBitmap(width, height, Bitmap.Config.ARGB_8888)
    outAlloc.copyTo(bmp)
    // cleanup
    inAlloc.destroy(); outAlloc.destroy(); yuvToRgb.destroy(); rs.destroy()

    if (rotationDegrees == 0) return bmp
    val matrix = Matrix().apply { postRotate(rotationDegrees.toFloat()) }
    return Bitmap.createBitmap(bmp, 0, 0, bmp.width, bmp.height, matrix, true)
  }
}
```
Notes: RenderScript may be deprecated on some SDKs; replace with ImageConverter / ScriptIntrinsic replacement if needed. This utility returns a rotated bitmap for direct OCR preprocessing.

2) Simple text-region detector (fast OpenCV-style preprocessing using OpenCV4Android or pure Android + morphological ops). This example assumes OpenCV is available and shows adaptive-threshold + dilate + findContours to produce bounding boxes to pass to recognizer.

- Add OpenCV dependency (example uses OpenCV SDK or OpenCV Android binding).
- Detector:
```kotlin
// TextRegionDetector.kt
import android.graphics.Bitmap
import org.opencv.android.Utils
import org.opencv.core.Core
import org.opencv.core.Mat
import org.opencv.core.Point
import org.opencv.core.Rect
import org.opencv.core.Scalar
import org.opencv.core.Size
import org.opencv.imgproc.Imgproc

object TextRegionDetector {
  // Returns list of android.graphics.Rect areas likely containing text (in image coords)
  fun detectTextRegions(bitmap: Bitmap): List<android.graphics.Rect> {
    val mat = Mat()
    Utils.bitmapToMat(bitmap, mat)
    Imgproc.cvtColor(mat, mat, Imgproc.COLOR_RGBA2GRAY)
    Imgproc.GaussianBlur(mat, mat, Size(3.0, 3.0), 0.0)
    val binary = Mat()
    Imgproc.adaptiveThreshold(mat, binary, 255.0, Imgproc.ADAPTIVE_THRESH_MEAN_C,
      Imgproc.THRESH_BINARY_INV, 15, 10.0)
    val kernel = Imgproc.getStructuringElement(Imgproc.MORPH_RECT, Size(9.0, 3.0))
    Imgproc.morphologyEx(binary, binary, Imgproc.MORPH_CLOSE, kernel)
    val contours = ArrayList<MatOfPoint>()
    val hierarchy = Mat()
    Imgproc.findContours(binary, contours, hierarchy, Imgproc.RETR_EXTERNAL, Imgproc.CHAIN_APPROX_SIMPLE)
    val boxes = ArrayList<android.graphics.Rect>()
    for (cnt in contours) {
      val r = Imgproc.boundingRect(cnt)
      // Filter by aspect ratio and size to reduce false positives
      if (r.width > 50 && r.height > 15 && r.width.toDouble() / r.height.toDouble() > 2.0) {
        boxes.add(android.graphics.Rect(r.x, r.y, r.x + r.width, r.y + r.height))
      }
      cnt.release()
    }
    mat.release(); binary.release(); hierarchy.release()
    return boxes
  }
}
```
Usage notes:
- Call TextRegionDetector.detectTextRegions(bitmap) after ImageUtils.yuvToBitmap(...) to get ROI rectangles.
- Crop bitmap to each rect, resize to recognizer input height (e.g., 32 px) preserving aspect, then pass to ONNX recognizer or TessCameraOcr preprocessing.
- For speed, only run detection every N frames and run recognizer on stable ROIs across frames.

