```kotlin
package com.example.onnxocr

import android.Manifest
import android.content.pm.PackageManager
import android.os.Bundle
import android.widget.Toast
import androidx.activity.result.contract.ActivityResultContracts
import androidx.appcompat.app.AppCompatActivity
import androidx.camera.view.PreviewView
import androidx.core.content.ContextCompat

class MainActivity : AppCompatActivity() {
  private lateinit var previewView: PreviewView
  private var ocr: ONNXCameraOcr? = null

  private val requestPermission = registerForActivityResult(ActivityResultContracts.RequestPermission()) { granted ->
    if (granted) startOcr() else Toast.makeText(this, "Camera permission required", Toast.LENGTH_LONG).show()
  }

  override fun onCreate(savedInstanceState: Bundle?) {
    super.onCreate(savedInstanceState)
    previewView = PreviewView(this)
    setContentView(previewView)
    if (ContextCompat.checkSelfPermission(this, Manifest.permission.CAMERA) != PackageManager.PERMISSION_GRANTED) {
      requestPermission.launch(Manifest.permission.CAMERA)
    } else startOcr()
  }

  private fun startOcr() {
    // modelPath is asset path copied to app files dir on startup
    val modelPath = copyAssetModelToFiles("models/ocr_recognizer.onnx")
    val labelsPath = copyAssetModelToFiles("models/labels.txt")
    ocr = ONNXCameraOcr(this, this, previewView, modelPath, labelsPath) { text ->
      // Callback with recognized text; forward to existing speech/command system
      runOnUiThread { Toast.makeText(this, text.take(200), Toast.LENGTH_SHORT).show() }
    }
    ocr?.start()
  }

  override fun onDestroy() {
    super.onDestroy()
    ocr?.stop()
  }

  private fun copyAssetModelToFiles(assetPath: String): String {
    val f = java.io.File(filesDir, assetPath)
    if (!f.exists()) {
      f.parentFile?.mkdirs()
      assets.open(assetPath).use { input -> f.outputStream().use { out -> input.copyTo(out) } }
    }
    return f.absolutePath
  }
}
```

4) ONNXCameraOcr.kt
```kotlin
package com.example.onnxocr

import android.content.Context
import android.graphics.Bitmap
import androidx.camera.core.CameraSelector
import androidx.camera.core.ImageAnalysis
import androidx.camera.core.ImageProxy
import androidx.camera.lifecycle.ProcessCameraProvider
import androidx.camera.view.PreviewView
import androidx.core.content.ContextCompat
import kotlinx.coroutines.*
import ai.onnxruntime.*

class ONNXCameraOcr(
  private val context: Context,
  private val lifecycleOwner: androidx.lifecycle.LifecycleOwner,
  private val previewView: PreviewView,
  modelPath: String,
  labelsPath: String,
  private val onText: (String) -> Unit
) {
  private val scope = CoroutineScope(Dispatchers.Default + SupervisorJob())
  private val env = OrtEnvironment.getEnvironment()
  private val session: OrtSession = env.createSession(modelPath, OrtSession.SessionOptions())
  private val labels = loadLabels(labelsPath)

  fun start() {
    val cameraProviderFuture = ProcessCameraProvider.getInstance(context)
    cameraProviderFuture.addListener({
      val cameraProvider = cameraProviderFuture.get()
      val analysis = ImageAnalysis.Builder()
        .setBackpressureStrategy(ImageAnalysis.STRATEGY_KEEP_ONLY_LATEST)
        .build()
      analysis.setAnalyzer(ContextCompat.getMainExecutor(context)) { image -> analyze(image) }
      val selector = CameraSelector.DEFAULT_BACK_CAMERA
      cameraProvider.unbindAll()
      cameraProvider.bindToLifecycle(lifecycleOwner, selector, analysis)
    }, ContextCompat.getMainExecutor(context))
  }

  private fun analyze(imageProxy: ImageProxy) {
    val mediaImage = imageProxy.image
    if (mediaImage == null) { imageProxy.close(); return }
    scope.launch {
      try {
        val bmp = ImageUtils.yuvToBitmap(context, mediaImage, imageProxy.imageInfo.rotationDegrees)
        val regions = TextRegionDetector.detectTextRegions(bmp)
        // For each region run recognizer; here process first region for brevity
        if (regions.isNotEmpty()) {
          val r = regions[0]
          val crop = Bitmap.createBitmap(bmp, r.left, r.top, r.width(), r.height())
          val input = preprocessForRecognizer(crop) // FloatBuffer or float array shaped to model
          val tensor = OnnxTensor.createTensor(env, input, longArrayOf(1, 3, 32, inputWidth(input)))
          val result = session.run(mapOf(session.inputNames.iterator().next() to tensor))
          val out = result[0].value as Array<FloatArray>
          val text = ctcDecode(out)
          if (text.isNotBlank()) withContext(Dispatchers.Main) { onText(text) }
        }
      } catch (e: Exception) {
        // ignore/log
      } finally { imageProxy.close() }
    }
  }

  private fun loadLabels(path: String): List<String> =
    java.io.File(path).readLines().map { it.trim() }

  private fun ctcDecode(output: Array<FloatArray>): String {
    val sb = StringBuilder()
    var prev = -1
    for (t in output.indices) {
      val row = output[t]
      var maxIdx = 0; var maxV = row[0]
      for (i in 1 until row.size) if (row[i] > maxV) { maxV = row[i]; maxIdx = i }
      if (maxIdx != prev && maxIdx != 0) sb.append(labels.getOrNull(maxIdx) ?: "")
      prev = maxIdx
    }
    return sb.toString()
  }

  private fun inputWidth(input: Any): Long {
    // implement according to your tensor shape; return width dim used when creating tensor
    return 320
  }

  private fun preprocessForRecognizer(bitmap: Bitmap): FloatArray {
    val targetH = 32
    val targetW = 320
    val resized = Bitmap.createScaledBitmap(bitmap, targetW, targetH, true)
    val pixels = IntArray(targetW * targetH)
    resized.getPixels(pixels, 0, targetW, 0, 0, targetW, targetH)
    val out = FloatArray(3 * targetH * targetW)
    var idx = 0
    for (p in pixels) {
      val r = ((p shr 16) and 0xFF) / 255.0f
      val g = ((p shr 8) and 0xFF) / 255.0f
      val b = (p and 0xFF) / 255.0f
      out[idx++] = r; out[idx++] = g; out[idx++] = b
    }
    return out
  }

  fun stop() {
    scope.cancel(); session.close(); env.close()
  }
}
```

5) ImageUtils.kt (YUV -> Bitmap using RenderScript)
```kotlin
package com.example.onnxocr

import android.content.Context
import android.graphics.Bitmap
import android.graphics.Matrix
import android.media.Image
import android.renderscript.*

object ImageUtils {
  fun yuvToBitmap(context: Context, image: Image, rotationDegrees: Int = 0): Bitmap {
    val width = image.width; val height = image.height
    val yuv = yuv420ToNv21(image)
    val rs = RenderScript.create(context)
    val inAlloc = Allocation.createSized(rs, Element.U8(rs), yuv.size)
    inAlloc.copyFrom(yuv)
    val outAlloc = Allocation.createTyped(rs, Type.Builder(rs, Element.RGBA_8888(rs)).setX(width).setY(height).create())
    val script = ScriptIntrinsicYuvToRGB.create(rs, Element.U8_4(rs))
    script.setInput(inAlloc)
    script.forEach(outAlloc)
    val bmp = Bitmap.createBitmap(width, height, Bitmap.Config.ARGB_8888)
    outAlloc.copyTo(bmp)
    inAlloc.destroy(); outAlloc.destroy(); script.destroy(); rs.destroy()
    if (rotationDegrees == 0) return bmp
    val matrix = Matrix().apply { postRotate(rotationDegrees.toFloat()) }
    return Bitmap.createBitmap(bmp, 0, 0, bmp.width, bmp.height, matrix, true)
  }

  private fun yuv420ToNv21(image: Image): ByteArray {
    val ySize = image.planes[0].buffer.remaining()
    val uSize = image.planes[1].buffer.remaining()
    val vSize = image.planes[2].buffer.remaining()
    val nv21 = ByteArray(ySize + uSize + vSize)
    image.planes[0].buffer.get(nv21, 0, ySize)
    val rowStride = image.planes[1].rowStride
    val pixelStride = image.planes[1].pixelStride
    val uBuffer = ByteArray(uSize).also { image.planes[1].buffer.get(it) }
    val vBuffer = ByteArray(vSize).also { image.planes[2].buffer.get(it) }
    var offset = ySize
    val height = image.height
    val chromaHeight = height / 2
    var pos = 0
    for (row in 0 until chromaHeight) {
      for (col in 0 until image.width / 2) {
        nv21[offset + pos] = vBuffer[row * rowStride + col * pixelStride]
        nv21[offset + pos + 1] = uBuffer[row * rowStride + col * pixelStride]
        pos += 2
      }
    }
    return nv21
  }
}
```

